export const UI_VOCABULARY_SCHEMA_VERSION = "2026-06-09.ui-vocabulary";
export const UI_PROP_SCHEMA_VERSION = "2026-06-09.ui-props";
export const UI_VOCABULARY_HANDSHAKE_VERSION = "2026-06-09.vocabulary-handshake";
export const UI_PAYLOAD_SCHEMA_VERSION = "2026-06-09";

export const vocabularyHandshake = Object.freeze({
  schemaVersion: UI_VOCABULARY_HANDSHAKE_VERSION,
  payloadSchemaVersions: Object.freeze([UI_PAYLOAD_SCHEMA_VERSION]),
  componentNamespace: "@jami-studio/ui",
  componentVersion: "0.0.0",
  propSchemaVersion: UI_PROP_SCHEMA_VERSION,
  vocabularyVersion: UI_VOCABULARY_SCHEMA_VERSION,
  generation: Object.freeze({
    source: "registry-addressable-resident-vocabulary",
    unsupportedComponentState: "unsupported",
    invalidPropState: "invalid",
    actions: "display-only actionRefs; execution stays in Jami Harness",
    copiedSource: false,
  }),
});

const baseStates = [
  "keyboard",
  "focus-visible",
  "aria",
  "contrast",
  "reduced-motion",
  "responsive",
  "disabled",
  "loading",
  "invalid",
  "empty",
  "error",
  "long-content",
];

function defineComponent(definition) {
  return Object.freeze({
    schemaVersion: UI_VOCABULARY_SCHEMA_VERSION,
    namespace: "@jami-studio/ui",
    provenance: {
      source: "authored",
      license: "MIT",
      reviewedAt: "2026-06-09",
      copiedSource: false,
    },
    ...definition,
    tokens: Object.freeze(definition.tokens),
    states: Object.freeze(definition.states),
    propSchema: deepFreeze({
      schemaVersion: UI_PROP_SCHEMA_VERSION,
      additionalProperties: false,
      required: [],
      ...definition.propSchema,
    }),
  });
}

function deepFreeze(value) {
  if (value && typeof value === "object") {
    Object.freeze(value);
    for (const item of Object.values(value)) deepFreeze(item);
  }
  return value;
}

function stringProp({ enumValues, pattern, nullable = false } = {}) {
  return {
    type: "string",
    ...(enumValues ? { enum: enumValues } : {}),
    ...(pattern ? { pattern } : {}),
    ...(nullable ? { nullable: true } : {}),
  };
}

function booleanProp() {
  return { type: "boolean" };
}

function arrayProp({ itemType = "object", pattern } = {}) {
  return { type: "array", items: { type: itemType, ...(pattern ? { pattern } : {}) } };
}

const actionRefProp = arrayProp({ itemType: "string", pattern: "^act_[a-z0-9][a-z0-9_-]*$" });
const artifactViewRefProp = arrayProp({ itemType: "string", pattern: "^artv_[a-z0-9][a-z0-9_-]*$" });

export const componentVocabulary = Object.freeze([
  defineComponent({
    name: "button",
    kind: "primitive",
    registryItem: "@jami-studio/button",
    description: "Tokenized action surface for command slots and form actions.",
    tokens: [
      "semantic.light.accent",
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.dark.accent",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
      "motion.fast",
    ],
    states: baseStates,
    aria: {
      role: "button",
      labelSource: "label | ariaLabel",
      disabledAttribute: "disabled",
      busyAttribute: "aria-busy",
    },
    propSchema: {
      properties: {
        label: stringProp(),
        ariaLabel: stringProp(),
        variant: stringProp({ enumValues: ["primary", "secondary", "ghost", "danger"] }),
        size: stringProp({ enumValues: ["compact", "regular"] }),
        disabled: booleanProp(),
        loading: booleanProp(),
        actionRef: stringProp({ pattern: "^act_[a-z0-9][a-z0-9_-]*$" }),
      },
    },
  }),
  defineComponent({
    name: "panel",
    kind: "primitive",
    registryItem: "@jami-studio/panel",
    description: "Low-radius tokenized surface for cards, docks, and grouped content.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.dark.background",
      "semantic.dark.foreground",
      "componentState.focusRing",
      "radius.control",
      "shadow.overlay",
    ],
    states: baseStates,
    aria: {
      role: "region",
      labelSource: "title | ariaLabel",
      emptyState: "aria-live=polite",
    },
    propSchema: {
      properties: {
        title: stringProp(),
        ariaLabel: stringProp(),
        tone: stringProp({ enumValues: ["neutral", "accent", "danger"] }),
        empty: booleanProp(),
        error: stringProp(),
      },
    },
  }),
  defineComponent({
    name: "text-field",
    kind: "primitive",
    registryItem: "@jami-studio/text-field",
    description: "Labelled input field with invalid, disabled, loading, and helper states.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.light.accent",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
      "motion.fast",
    ],
    states: baseStates,
    aria: {
      role: "textbox",
      labelSource: "label",
      invalidAttribute: "aria-invalid",
      describedBy: "helperText | errorText",
    },
    propSchema: {
      required: ["label"],
      properties: {
        label: stringProp(),
        value: stringProp(),
        placeholder: stringProp(),
        disabled: booleanProp(),
        invalid: booleanProp(),
        errorText: stringProp(),
        helperText: stringProp(),
      },
    },
  }),
  defineComponent({
    name: "data-list",
    kind: "component",
    registryItem: "@jami-studio/data-list",
    description: "Responsive table/list display for dense operational records.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.dark.background",
      "semantic.dark.foreground",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
    ],
    states: baseStates,
    aria: {
      role: "table | list",
      labelSource: "title | ariaLabel",
      emptyState: "status",
    },
    propSchema: {
      properties: {
        title: stringProp(),
        ariaLabel: stringProp(),
        columns: arrayProp(),
        rows: arrayProp(),
        empty: booleanProp(),
        loading: booleanProp(),
        error: stringProp(),
      },
    },
  }),
  defineComponent({
    name: "agent-panel",
    kind: "component",
    registryItem: "@jami-studio/agent-panel",
    description: "Display-only agent status, pending approval, denied action, and error panel.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.light.accent",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
    ],
    states: baseStates,
    aria: {
      role: "status",
      labelSource: "title | agentName",
      liveRegion: "polite",
    },
    propSchema: {
      properties: {
        title: stringProp(),
        agentName: stringProp(),
        status: stringProp({ enumValues: ["idle", "running", "needs_attention", "denied", "error"] }),
        actionRefs: actionRefProp,
        artifactViewRefs: artifactViewRefProp,
      },
    },
  }),
  defineComponent({
    name: "docs-source-panel",
    kind: "component",
    registryItem: "@jami-studio/docs-source-panel",
    description: "Source, citation, and document reference panel with redaction-aware states.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.dark.background",
      "semantic.dark.foreground",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
    ],
    states: baseStates,
    aria: {
      role: "complementary",
      labelSource: "title | ariaLabel",
      redactionState: "aria-describedby",
    },
    propSchema: {
      properties: {
        title: stringProp(),
        ariaLabel: stringProp(),
        sources: arrayProp(),
        selectedSourceId: stringProp(),
        redacted: booleanProp(),
        empty: booleanProp(),
      },
    },
  }),
  defineComponent({
    name: "media-grid",
    kind: "component",
    registryItem: "@jami-studio/media-grid",
    description: "Responsive media and artifact gallery with empty/error/loading states.",
    tokens: [
      "semantic.light.background",
      "semantic.light.foreground",
      "semantic.dark.background",
      "semantic.dark.foreground",
      "componentState.focusRing",
      "spacing.control",
      "radius.control",
      "motion.fast",
    ],
    states: baseStates,
    aria: {
      role: "list",
      labelSource: "title | ariaLabel",
      itemRole: "listitem",
    },
    propSchema: {
      properties: {
        title: stringProp(),
        ariaLabel: stringProp(),
        items: arrayProp(),
        selectedItemId: stringProp(),
        loading: booleanProp(),
        empty: booleanProp(),
        error: stringProp(),
      },
    },
  }),
]);

const byName = new Map(componentVocabulary.map((definition) => [definition.name, definition]));

export const registryAddressableNames = Object.freeze([...byName.keys()]);

export const stateFixtureMatrix = Object.freeze(
  Object.fromEntries(componentVocabulary.map((definition) => [definition.name, definition.states])),
);

export function getComponentDefinition(name) {
  return byName.get(name) ?? null;
}

function valueType(value) {
  if (Array.isArray(value)) return "array";
  if (value === null) return "null";
  return typeof value;
}

function validateValue(propName, value, rule, issues) {
  const actual = valueType(value);
  if (value === null && rule.nullable) return;
  if (actual !== rule.type) {
    issues.push(`prop ${propName} must be ${rule.type}`);
    return;
  }
  if (rule.enum && !rule.enum.includes(value)) {
    issues.push(`prop ${propName} must be one of ${rule.enum.join(", ")}`);
  }
  if (rule.pattern && typeof value === "string" && !new RegExp(rule.pattern).test(value)) {
    issues.push(`prop ${propName} does not match ${rule.pattern}`);
  }
  if (rule.type === "array" && rule.items) {
    for (const [index, item] of value.entries()) {
      validateValue(`${propName}[${index}]`, item, rule.items, issues);
    }
  }
}

export function validateComponentProps(componentName, props) {
  const definition = getComponentDefinition(componentName);
  if (!definition) return [`component ${componentName} has no prop schema`];
  if (props === undefined) return [];
  if (!props || typeof props !== "object" || Array.isArray(props)) {
    return [`props for ${componentName} must be an object`];
  }
  const schema = definition.propSchema;
  const issues = [];
  const properties = schema.properties ?? {};
  for (const required of schema.required ?? []) {
    if (!Object.hasOwn(props, required)) issues.push(`missing required prop ${required}`);
  }
  if (schema.additionalProperties === false) {
    for (const key of Object.keys(props)) {
      if (!Object.hasOwn(properties, key)) issues.push(`unsupported prop ${key} for ${componentName}`);
    }
  }
  for (const [key, value] of Object.entries(props)) {
    const rule = properties[key];
    if (rule) validateValue(key, value, rule, issues);
  }
  return issues;
}

/* Authored Studio UI resident vocabulary styles. Token variables are generated by packages/tokens. */
.jami-ui {
  color: var(--jami-semantic-light-foreground);
  background: var(--jami-semantic-light-background);
  font: var(--jami-typography-body);
}

.jami-button {
  align-items: center;
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 18%, transparent);
  border-radius: var(--jami-radius-control);
  display: inline-flex;
  gap: var(--jami-spacing-control);
  justify-content: center;
  min-height: calc(var(--jami-spacing-control) * 5);
  padding: var(--jami-spacing-control) calc(var(--jami-spacing-control) * 1.5);
  transition-duration: var(--jami-motion-fast);
  transition-property: background-color, border-color, box-shadow, color;
}

.jami-button[data-variant="primary"] {
  background: var(--jami-semantic-light-accent);
  color: var(--jami-semantic-dark-foreground);
}

.jami-button:focus-visible,
.jami-panel:focus-visible,
.jami-field input:focus-visible,
.jami-data-list:focus-visible,
.jami-agent-panel:focus-visible,
.jami-docs-source-panel:focus-visible,
.jami-media-grid:focus-visible {
  outline: 2px solid var(--jami-componentState-focusRing);
  outline-offset: 2px;
}

.jami-button[disabled],
.jami-field input[disabled],
[aria-disabled="true"] {
  cursor: not-allowed;
  opacity: 0.58;
}

.jami-panel,
.jami-data-list,
.jami-agent-panel,
.jami-docs-source-panel,
.jami-media-grid {
  background: var(--jami-semantic-light-background);
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 14%, transparent);
  border-radius: var(--jami-radius-control);
  box-shadow: var(--jami-shadow-overlay);
  color: var(--jami-semantic-light-foreground);
  min-width: 0;
  overflow-wrap: anywhere;
  padding: calc(var(--jami-spacing-control) * 2);
}

.jami-field {
  display: grid;
  gap: var(--jami-spacing-control);
}

.jami-field input {
  background: var(--jami-semantic-light-background);
  border: 1px solid color-mix(in srgb, var(--jami-semantic-light-foreground) 18%, transparent);
  border-radius: var(--jami-radius-control);
  color: var(--jami-semantic-light-foreground);
  min-height: calc(var(--jami-spacing-control) * 5);
  padding: var(--jami-spacing-control);
}

.jami-field [aria-invalid="true"] {
  border-color: var(--jami-semantic-light-accent);
}

.jami-data-list {
  display: grid;
  gap: var(--jami-spacing-control);
}

.jami-media-grid {
  display: grid;
  gap: var(--jami-spacing-control);
  grid-template-columns: repeat(auto-fit, minmax(10rem, 1fr));
}

@media (prefers-reduced-motion: reduce) {
  .jami-button {
    transition-duration: 0ms;
  }
}

@media (prefers-color-scheme: dark) {
  .jami-ui {
    color: var(--jami-semantic-dark-foreground);
    background: var(--jami-semantic-dark-background);
  }

  .jami-panel,
  .jami-data-list,
  .jami-agent-panel,
  .jami-docs-source-panel,
  .jami-media-grid,
  .jami-field input {
    color: var(--jami-semantic-dark-foreground);
    background: var(--jami-semantic-dark-background);
  }
}

import { componentVocabulary, vocabularyHandshake } from "./vocabulary.mjs";

function descriptor(definition, element, slots = []) {
  return Object.freeze({
    schemaVersion: "2026-06-09.primitive-descriptor",
    component: definition.name,
    registryItem: definition.registryItem,
    namespace: definition.namespace,
    vocabularyHandshake: vocabularyHandshake.schemaVersion,
    sourceKind: "react-style-descriptor",
    implementationStatus: "framework-neutral-component-factory",
    implementationSource: "packages/ui/src/primitive-components.mjs",
    radixWrapper: false,
    runtimeReactRenderer: false,
    element,
    slots: Object.freeze(slots),
    propSchemaVersion: definition.propSchema.schemaVersion,
    propSchema: definition.propSchema,
    a11y: definition.aria,
    provenance: definition.provenance,
  });
}

const definitions = new Map(componentVocabulary.map((definition) => [definition.name, definition]));

export const primitiveDescriptors = Object.freeze({
  button: descriptor(definitions.get("button"), "button", ["children", "actionRef"]),
  panel: descriptor(definitions.get("panel"), "section", ["title", "children"]),
  "text-field": descriptor(definitions.get("text-field"), "input", ["label", "helperText", "errorText"]),
  "data-list": descriptor(definitions.get("data-list"), "table | ul", ["columns", "rows", "empty"]),
  "agent-panel": descriptor(definitions.get("agent-panel"), "section", ["status", "actionRefs", "artifactViewRefs"]),
  "docs-source-panel": descriptor(definitions.get("docs-source-panel"), "aside", ["sources", "selectedSourceId"]),
  "media-grid": descriptor(definitions.get("media-grid"), "ul", ["items", "selectedItemId"]),
});

export function getPrimitiveDescriptor(name) {
  return primitiveDescriptors[name] ?? null;
}

import {
  componentVocabulary,
  getComponentDefinition,
  validateComponentProps,
  vocabularyHandshake,
} from "./vocabulary.mjs";

export const PRIMITIVE_COMPONENT_IMPLEMENTATION_VERSION =
  "2026-06-09.framework-neutral-component-factory";

const byName = new Map(componentVocabulary.map((definition) => [definition.name, definition]));

function compactProps(props) {
  const out = {};
  for (const [key, value] of Object.entries(props)) {
    if (value !== undefined && value !== null && value !== false) out[key] = value;
  }
  return out;
}

function element(type, props = {}, ...children) {
  return {
    type,
    props: compactProps(props),
    children: children.flat().filter((child) => child !== undefined && child !== null && child !== false),
  };
}

function text(value) {
  return String(value ?? "");
}

function fallbackText(value, fallback) {
  const normalized = text(value).trim();
  return normalized.length > 0 ? normalized : fallback;
}

function slug(value) {
  const normalized = text(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
  return normalized || "field";
}

function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function displayValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "function" || typeof value === "symbol") return "[unsupported value]";
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch {
      return "[unserializable value]";
    }
  }
  return String(value);
}

function safeChild(value) {
  if (value === undefined || value === null || value === false) return null;
  return displayValue(value);
}

function safeChildren(value) {
  const values = Array.isArray(value) ? value.flat(Infinity) : [value];
  return values.map(safeChild).filter((child) => child !== null);
}

function childrenOrLabel(props, fallback) {
  if (props.children !== undefined) return safeChildren(props.children);
  if (props.label !== undefined) return [text(props.label)];
  return [fallback];
}

function normalizeVariant(value, fallback, allowed) {
  return allowed.includes(value) ? value : fallback;
}

function renderButton(props = {}) {
  const variant = normalizeVariant(props.variant, "primary", ["primary", "secondary", "ghost", "danger"]);
  const size = normalizeVariant(props.size, "regular", ["compact", "regular"]);
  const label = fallbackText(props.label ?? props.ariaLabel, props.loading ? "Loading" : "Action");
  return element(
    "button",
    {
      type: "button",
      className: "jami-button",
      "data-variant": variant,
      "data-size": size,
      "data-action-ref": props.actionRef,
      disabled: props.disabled || props.loading,
      "aria-busy": props.loading ? "true" : undefined,
      "aria-label": props.ariaLabel && !props.label ? props.ariaLabel : undefined,
    },
    ...childrenOrLabel({ ...props, label }, label),
  );
}

function renderPanel(props = {}) {
  const tone = normalizeVariant(props.tone, "neutral", ["neutral", "accent", "danger"]);
  const title = props.title ? element("h3", { className: "jami-panel-title" }, text(props.title)) : null;
  const body =
    props.empty === true
      ? element("p", { role: "status" }, "No content yet.")
      : props.error
        ? element("p", { role: "alert" }, text(props.error))
        : safeChildren(props.children);
  return element(
    "section",
    {
      className: "jami-panel",
      "data-tone": tone,
      "data-empty": props.empty ? "true" : undefined,
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Panel",
    },
    title,
    ...body,
  );
}

function renderTextField(props = {}) {
  const id = `jami-field-${slug(props.label)}`;
  const helpId = props.helperText || props.errorText ? `${id}-help` : undefined;
  return element(
    "label",
    { className: "jami-field", htmlFor: id },
    element("span", { className: "jami-field-label" }, fallbackText(props.label, "Field")),
    element("input", {
      id,
      name: id,
      type: "text",
      defaultValue: props.value,
      placeholder: props.placeholder,
      disabled: props.disabled,
      "aria-invalid": props.invalid ? "true" : undefined,
      "aria-describedby": helpId,
    }),
    props.errorText
      ? element("span", { id: helpId, role: "alert" }, text(props.errorText))
      : props.helperText
        ? element("span", { id: helpId }, text(props.helperText))
        : null,
  );
}

function columnKey(column, index) {
  if (typeof column === "string") return column;
  return column?.key ?? `column-${index + 1}`;
}

function columnLabel(column, index) {
  if (typeof column === "string") return column;
  return column?.label ?? column?.key ?? `Column ${index + 1}`;
}

function renderDataList(props = {}) {
  const columns = safeArray(props.columns);
  const rows = safeArray(props.rows);
  const title = props.title ? element("h3", { className: "jami-data-list-title" }, text(props.title)) : null;
  const status =
    props.loading || props.empty || props.error || rows.length === 0
      ? element(
          "p",
          { role: props.error ? "alert" : "status" },
          props.error ? text(props.error) : props.loading ? "Loading records." : "No records to display.",
        )
      : null;
  const table =
    columns.length > 0 && rows.length > 0
      ? element(
          "table",
          { className: "jami-data-list-table" },
          element(
            "thead",
            {},
            element(
              "tr",
              {},
              ...columns.map((column, index) =>
                element("th", { scope: "col" }, text(columnLabel(column, index))),
              ),
            ),
          ),
          element(
            "tbody",
            {},
            ...rows.map((row) =>
              element(
                "tr",
                {},
                ...columns.map((column, index) =>
                  element("td", {}, displayValue(row?.[columnKey(column, index)])),
                ),
              ),
            ),
          ),
        )
      : null;
  return element(
    "section",
    {
      className: "jami-data-list",
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Data list",
      "aria-busy": props.loading ? "true" : undefined,
    },
    title,
    status,
    table,
  );
}

function renderAgentPanel(props = {}) {
  const status = normalizeVariant(props.status, "idle", [
    "idle",
    "running",
    "needs_attention",
    "denied",
    "error",
  ]);
  const actionRefs = safeArray(props.actionRefs);
  const artifactViewRefs = safeArray(props.artifactViewRefs);
  return element(
    "section",
    {
      className: "jami-agent-panel",
      role: "status",
      "aria-live": "polite",
      "aria-label": props.title ?? props.agentName ?? "Agent status",
      "data-status": status,
    },
    element("h3", {}, fallbackText(props.title ?? props.agentName, "Agent")),
    element("p", {}, status.replaceAll("_", " ")),
    actionRefs.length
      ? element(
          "ul",
          { className: "jami-action-ref-list", "aria-label": "Action references" },
          ...actionRefs.map((ref) => element("li", { "data-action-ref": ref }, text(ref))),
        )
      : null,
    artifactViewRefs.length
      ? element(
          "ul",
          { className: "jami-artifact-ref-list", "aria-label": "Artifact view references" },
          ...artifactViewRefs.map((ref) => element("li", { "data-artifact-view-ref": ref }, text(ref))),
        )
      : null,
  );
}

function sourceId(source, index) {
  return source?.id ?? source?.sourceId ?? `source-${index + 1}`;
}

function sourceTitle(source, index) {
  return source?.title ?? source?.label ?? sourceId(source, index);
}

function renderDocsSourcePanel(props = {}) {
  const sources = safeArray(props.sources);
  const selectedSourceId = props.selectedSourceId ?? null;
  return element(
    "aside",
    {
      className: "jami-docs-source-panel",
      role: "complementary",
      "aria-label": props.ariaLabel ?? props.title ?? "Sources",
      "data-redacted": props.redacted ? "true" : undefined,
    },
    element("h3", {}, fallbackText(props.title, "Sources")),
    props.redacted ? element("p", { role: "status" }, "Source details are redacted.") : null,
    props.empty || sources.length === 0
      ? element("p", { role: "status" }, "No sources attached.")
      : element(
          "ul",
          { className: "jami-source-list" },
          ...sources.map((source, index) =>
            element(
              "li",
              {
                "data-source-id": sourceId(source, index),
                "aria-current": selectedSourceId === sourceId(source, index) ? "true" : undefined,
              },
              text(sourceTitle(source, index)),
            ),
          ),
        ),
  );
}

function mediaItemId(item, index) {
  return item?.id ?? item?.artifactId ?? `media-${index + 1}`;
}

function mediaItemLabel(item, index) {
  return item?.title ?? item?.label ?? item?.alt ?? mediaItemId(item, index);
}

function renderMediaGrid(props = {}) {
  const items = safeArray(props.items);
  const selectedItemId = props.selectedItemId ?? null;
  const status =
    props.error || props.loading || props.empty || items.length === 0
      ? element(
          "p",
          { role: props.error ? "alert" : "status" },
          props.error ? text(props.error) : props.loading ? "Loading media." : "No media items.",
        )
      : null;
  return element(
    "section",
    {
      className: "jami-media-grid",
      role: "region",
      "aria-label": props.ariaLabel ?? props.title ?? "Media",
      "aria-busy": props.loading ? "true" : undefined,
    },
    props.title ? element("h3", {}, text(props.title)) : null,
    status,
    items.length
      ? element(
          "ul",
          { className: "jami-media-grid-list" },
          ...items.map((item, index) =>
            element(
              "li",
              {
                "data-media-id": mediaItemId(item, index),
                "aria-current": selectedItemId === mediaItemId(item, index) ? "true" : undefined,
              },
              text(mediaItemLabel(item, index)),
            ),
          ),
        )
      : null,
  );
}

const renderers = Object.freeze({
  button: renderButton,
  panel: renderPanel,
  "text-field": renderTextField,
  "data-list": renderDataList,
  "agent-panel": renderAgentPanel,
  "docs-source-panel": renderDocsSourcePanel,
  "media-grid": renderMediaGrid,
});

export const primitiveComponentImplementations = Object.freeze(
  Object.fromEntries(
    componentVocabulary.map((definition) => [
      definition.name,
      Object.freeze({
        schemaVersion: PRIMITIVE_COMPONENT_IMPLEMENTATION_VERSION,
        component: definition.name,
        registryItem: definition.registryItem,
        namespace: definition.namespace,
        vocabularyHandshake: vocabularyHandshake.schemaVersion,
        propSchemaVersion: definition.propSchema.schemaVersion,
        implementationStatus: "framework-neutral-component-factory",
        source: "packages/ui/src/primitive-components.mjs",
        radixWrapper: false,
        runtimeReactRenderer: false,
        executableActions: false,
      }),
    ]),
  ),
);

export function getPrimitiveComponentImplementation(name) {
  return primitiveComponentImplementations[name] ?? null;
}

export function renderPrimitiveSpec(name, props = {}) {
  const definition = getComponentDefinition(name);
  if (!definition) {
    return {
      state: "unsupported",
      reasons: [`component ${name} is not part of the resident vocabulary`],
      node: element("section", { className: "jami-panel", role: "status" }, "Unsupported component."),
    };
  }
  const { children, ...schemaProps } = props;
  const reasons = validateComponentProps(name, schemaProps);
  if (reasons.length > 0) {
    return {
      state: "invalid",
      reasons,
      node: element("section", { className: "jami-panel", role: "alert", "data-tone": "danger" }, "Invalid props."),
    };
  }
  return {
    state: "renderable",
    reasons: [],
    node: renderers[name](props),
  };
}

export function createJamiPrimitiveComponents(createElement) {
  if (typeof createElement !== "function") {
    throw new TypeError("createJamiPrimitiveComponents requires a createElement function");
  }
  const fromSpec = (spec) => createElement(spec.type, spec.props, ...spec.children.map((child) => {
    if (child && typeof child === "object" && child.type && child.props && Array.isArray(child.children)) {
      return fromSpec(child);
    }
    return child;
  }));
  const make = (name) =>
    function JamiPrimitiveComponent(props = {}) {
      const result = renderPrimitiveSpec(name, props);
      return fromSpec(result.node);
    };
  return Object.freeze({
    Button: make("button"),
    Panel: make("panel"),
    TextField: make("text-field"),
    DataList: make("data-list"),
    AgentPanel: make("agent-panel"),
    DocsSourcePanel: make("docs-source-panel"),
    MediaGrid: make("media-grid"),
  });
}

export const primitiveComponentNames = Object.freeze([...byName.keys()]);
